def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(a, 10):
                    val = ((ratio - a) ** 4.5) / ((a + b) * 1.1 + 1)
                    trig = np.sin(ratio * b / (a + 0.7)) * np.cos(ratio * b) * np.tanh(val)
                    priority += val * trig * np.exp(-(ratio - a) / 2)
            priority += (np.tanh(ratio) * np.sin(ratio * 1.3) ** 2) ** 2.2
            if bin_cap < item * 0.7:
                priority += np.sqrt(item * bin_cap) * 3.7
            else:
                priority -= np.log1p(bin_cap / item) * 2.5
        elif 4 < ratio <= 8:
            total = 0
            for p in range(1, 6):
                for q in range(1, p + 4):
                    base = ((ratio - p) ** 3) / (q + 0.7)
                    mult = np.sin(ratio * q) * np.cos(p * ratio)
                    total += np.tanh(base) * mult
            priority = total * np.exp(-ratio / 4) * 9.2
            if i % 2 == 0:
                priority += np.log(ratio + 1) * 3.1
            else:
                priority -= np.tanh(ratio - 5) * 4.2
        elif 2 < ratio <= 4:
            s = 0
            for r in range(1, 16):
                s += ((ratio - 2) ** r) / (r * 2.3) * np.cos(r * ratio * 1.2)
            priority = s * np.sin(5 * ratio) - np.log(ratio) * 5 + np.tanh(3 * (4 - ratio)) * 2.7
            for n in range(1,5):
                priority += np.sin(n * ratio * i) * ((ratio - 2) ** n) / n
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 3.3
        elif 1 <= ratio <= 2:
            s = 0
            for m in range(1, 12):
                s += ((2 - ratio) ** m) / (m ** 2 + 0.9) * np.cos(m * ratio * 2)
            priority = s + np.exp(-ratio) * 4 - np.log1p(bin_cap) * 2
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.sin(15 * ratio) * 3
            priority += penalty
            for k in range(1, 6):
                priority += np.cos(k * ratio * i) * ((2 - ratio) ** k) / (k + 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 13):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.sin(n * item * 1.3)
            priority = s - np.log1p(bin_cap) * 1.5
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.tanh(bin_cap + ratio) * 2.7
            else:
                priority /= (np.sqrt(bin_cap + 0.7) + 1.5)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 18):
                s += ((0.5 - ratio) ** l) / (l * 5) * np.cos(l * ratio * 2.1)
            priority = s * np.tanh(bin_cap / (item + 1)) + 1 / (bin_cap + 2)
            if int(item * 1.6) % 6 == 0:
                priority *= 3.3
            else:
                priority /= 3.3
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.7) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 8) * np.cos(item * m * 0.9)
        else:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.3
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.9
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.9
        priorities[i] = priority
    return priorities
